head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
 ASIS에서 문법에 어긋난 문장이 발견되었습니다. 이는 WCRAFT에서 // ✖ 로 변환합니다.  
 // ✖ 로 변환된 곳을 찾아 ASIS소스를 참고하여 문법에 맞도록 변환해주세요. 

----------------------------------------------------
[0] 기존 문법 오류
----------------------------------------------------
	> // ✖ 오류 확인 - 기존 소스 확인 필요

*/


scwin.comList = Combo1.GetComboItems();

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {}; //조회구분 

//SEND DATA : 팝업.기준년월일(baseYmd)  =  현재일자
//GET  DATA : 부점명(brnName)           =  팝업.부점한글명(brnHanglName)
//팝업화면ID : KJI-04-811-000

scwin.Button2_OnClick = function(e) {
    Link.baseYmd = $c.user.getUserProfile('tranBaseYmd');
    $c.iz.screen.popup("KJI04811000", "DATALINK");
    var tempValue1 = Link.brncd;
    var tempValue2 = Link.brnHanglName;
    var tempValue3 = Link.brnName;
    if (tempValue1 != "" && typeof(tempValue1) != "undefined") {
        brncd.setValue(tempValue1);
        brnName.setValue(tempValue2);
    }
};

scwin.brncd_OnValidate = function(info) {
    //여기에 구현코드를 삽입하세요.
    $c.com.getCommonBrnName(brncd, brnName);
};

scwin.OnInitScreen = function() {
    brncd.setValue($c.user.getUserProfile('userBzwkBrncd'));
    brnName.setValue($c.user.getUserProfile('userBzwkBrnName'));
    inquryDte.setValue($c.user.getUserProfile('tranBaseYmd')); // 현재일자


    var menu_name = $c.iz.GetMenuPath().split('\\'); //메인메뉴		

    if (menu_name[2].indexOf('국고') > -1) cboupgb.SetCurSel(1);
    if (menu_name[2].indexOf('공금') > -1) cboupgb.SetCurSel(2);
    if (menu_name[2].indexOf('지로') > -1) cboupgb.SetCurSel(3);
    scwin.cboupgb_OnItemChanged();
};


scwin.OnSendKey = async function() {
    scwin.check_no_1 = "";
    array.removeAll();
    GroupBox3_4.setValue("");

    //[결과처리]
    //1. 결과를 그리드에 출력한다

    cboupgb_copy.setValue(cboupgb.getValue()); //업무구분
    Combo1_copy.setValue(Combo1.getValue()); //조회구분
    inquryDte_copy.setValue(inquryDte.getValue()); //조회일자
    ntresrAcno_copy.setValue(ntresrAcno.getValue()); //전자납부번호
    acno_copy.setValue(acno.getValue()); //국고계좌번호
    brncd_copy.setValue(brncd.getValue()); //점코드
    tranSerno_copy.setValue(''); //거래일련번호 



    $c.iz.tran.setTranID("KGA0400341");
    await $c.iz.tran.ASend();
};

//function Button3_OnClick(){

//array.ExcelExport(0,false,false, true,"-1", ";;;"+"|2|공과금전자수납거래내역조회", false, false, "", false, "", "", false, true); 
//  array.ExcelExports(0,false,false, true,"", ";;;"+"|2|공과금전자수납거래내역조회"); 

//}


scwin.Combo1_OnItemChanged = function(e) {
    acno.setValue();
    ntresrAcno.setValue();
    array.removeAll();
    switch (Combo1.getValue()) {
        case "4": //전자납부번호	
            ntresrAcno.setDisabled(false);
            ntresrAcno.setMandatory(true);
            acno.setDisabled(true);
            acno.setMandatory(false);
            brncd.setMandatory(false);
            brncd_copy.setMandatory(false);
            brncd.setDisabled(true);
            brncd.setValue();
            brnName.setValue();
            inquryDte.setMandatory(false);
            inquryDte_copy.setMandatory(false);
            inquryDte.setDisabled(false);
            inquryDte.setValue($c.user.getUserProfile('tranBaseYmd')); // 현재일자
            Button4.hide();
            Desc1.Visible = (cboupgb.getValue() == '2' || cboupgb.getValue() == '3') ? true : false;
            ntresrAcno.focus();
            break;
        case "5": //국고계좌번호	
            ntresrAcno.setDisabled(true);
            ntresrAcno.setMandatory(false);
            acno.setDisabled(false);
            acno.setMandatory(true);
            brncd.setMandatory(true);
            inquryDte.setMandatory(true);
            brncd.setDisabled(false);
            inquryDte.setDisabled(false);
            Button4.hide();
            Desc1.hide();
            acno.focus();
            break;
        default:
            ntresrAcno.setDisabled(true);
            ntresrAcno.setMandatory(false);
            acno.setDisabled(true);
            acno.setMandatory(false);
            brncd.setDisabled(false);
            inquryDte.setDisabled(false);
            brncd.setMandatory(true);
            inquryDte.setMandatory(true);
            inquryDte.setValue($c.user.getUserProfile('tranBaseYmd')); // 현재일자
            brncd.setValue($c.user.getUserProfile('userBzwkBrncd'));
            brnName.setValue($c.user.getUserProfile('userBzwkBrnName'));
            Button4.Visible = (cboupgb.getValue() == '2' || cboupgb.getValue() == '3') ? true : false;
            Desc1.hide();
            break;
    }
};


///////////////////////////////////////CANCLE////////////////////////////////////////////////////

scwin.check_no_1 = "";
scwin.check_no_2 = "";

scwin.array_OnClick = function(Arg1, Arg2, Arg3) {
    //한개의 그리드만 선택가능, 즉 한개의 그리드가 선택된 상태에서 다른 그리드를 선택하면 
    //먼저 선택된 그리드는 선택해제된다.
    //guid 를 확인해서 같은 guid 일경우는 모두 체크한다.



    if (Arg1 > 0) {
        if (scwin.check_no_2 != "") {
            array.setCellData(scwin.check_no_2, 0, "N");
            scwin.check_no_2 = "";
        }
        array.setCellData(Arg1, 0, "Y");
        scwin.check_no_2 = Arg1;
    }
    if (Arg1 > 0) {
        if (array.getCellData(Arg1, "bzwkDstic").indexOf('국고') > -1) return;
        if (scwin.check_no_1 != "") {
            array.setCellData(scwin.check_no_1, 0, "N");
            scwin.check_no_1 = "";
        }
        array.setCellData(Arg1, 0, "Y");
        scwin.check_no_1 = Arg1;
    }
};

scwin.Button4_OnClick = function(e) {
    scwin.Button_exe(2);
};



scwin.Button_exe = function(button_index) {
    if (array.GetCheckedRows(0) != 1) {
        $c.iz.data.message("해당 거래를 1개 선택해 주세요");
        return;
    }
    if (array.getCellData(scwin.check_no_1, "bzwkDstic").indexOf('국고') > -1) return;
    if (array.getCellData(scwin.check_no_1, "onecheck") == "Y") {
        //정상거래 확인 
        if (array.getCellData(scwin.check_no_1, "tranStus").indexOf("정상") < 0) {
            $c.iz.data.alert("정정거래는 정상거래에서만 가능합니다.", "알림");
            return;
        }
        var trancode = array.getCellData(scwin.check_no_1, "tranCd"); //거래코드

        Link.brncd = array.getCellData(scwin.check_no_1, "brncd"); //부점코드
        Link.rceitDte = array.getCellData(scwin.check_no_1, "rceitDte"); //수납일자
        Link.bzwkDstic = array.getCellData(scwin.check_no_1, "bzwkDstic"); //업무구분
        Link.tranSerno = array.getCellData(scwin.check_no_1, "tranSerno"); //거래일련번호
        Link.tranStus = array.getCellData(scwin.check_no_1, "tranStus"); //거래상태
        Link.tranAmt = array.getCellData(scwin.check_no_1, "tranAmt"); //거래금액
        Link.paymtzDstic = array.getCellData(scwin.check_no_1, "paymtzDstic"); //납부기한
        Link.rceitDsticName = array.getCellData(scwin.check_no_1, "rceitDsticName"); //수납구분명
        Link.elctrPaymtNo = array.getCellData(scwin.check_no_1, "elctrPaymtNo"); //전자납부번호
        Link.telgmNo = array.getCellData(scwin.check_no_1, "telgmNo"); //전문번호
        Link.drwotAcno = array.getCellData(scwin.check_no_1, "drwotAcno"); //출금계좌번호
        Link.tranHMS = array.getCellData(scwin.check_no_1, "tranHMS"); //거래시각
        Link.giroKnd = array.getCellData(scwin.check_no_1, "giroKnd"); //지로종류
        Link.ogtranGuid = array.getCellData(scwin.check_no_1, "ogtranGuid"); //원거래GUID	
        Link.cnclRstrInfoCtnt = array.getCellData(scwin.check_no_1, "cnclRstrInfoCtnt"); //취소복원정보내용
        Link.ogtranYMS = array.getCellData(scwin.check_no_1, "ogtranYMS"); //원거래일시

        if (trancode == "") {
            if (array.getCellData(scwin.check_no_1, "bzwkDstic").indexOf('공금') > -1) {
                Link.tranCd = "KGA0100113";
            } else {
                Link.tranCd = "KGA0100114";
            }
        } else {
            Link.tranCd = trancode;
        }

        //취소거래구분 설정 ex)   8:정정,	0:상세 			
        Link.cnclCd = button_index == 0 ? "0" : "8";
    }
    $c.iz.screen.popup("KGA04003101", "DATALINK");
    return;
};

scwin.array_OnDClick = function(Arg1, Arg2, Arg3) {
    scwin.array_OnClick(Arg1, 0, Arg3);
};


scwin.cboupgb_OnItemChanged = function(e) {
    Combo1.ClearComboData(); //조회구분초기화 

    switch (cboupgb.getValue()) {
        case '0': //전체 

            Combo1.AddComboItems("4-전자납부번호;");
            Combo1.SetCurSel(0);
            Combo1.setDisabled(true);
            Button4.hide();
            Btn_receipt.hide();
            break;
        case '1': //국고	  		
            Combo1.SetComboItems(scwin.comList);
            Combo1.DeleteItemByKey("6");
            Button4.hide();
            Btn_receipt.show('');
            Combo1.setDisabled(false);
            Combo1.SetCurSel(0);
            break;
        case '2': //공금	

            Combo1.SetComboItems(scwin.comList);
            Combo1.DeleteItemByKey("3");
            Combo1.DeleteItemByKey("5");
            Combo1.DeleteItemByKey("6");
            Button4.show('');
            Btn_receipt.hide();
            Combo1.setDisabled(false);
            Combo1.SetCurSel(0);
            break;
        case '3': //지로

            Combo1.SetComboItems(scwin.comList);
            Combo1.DeleteItemByKey("3");
            Combo1.DeleteItemByKey("5");
            Button4.show('');
            Btn_receipt.hide();
            Combo1.setDisabled(false);
            Combo1.SetCurSel(0);
            break;
        default:
            Button4.hide();
            Btn_receipt.hide();
            Combo1.setDisabled(false);
            Combo1.SetCurSel(0);
            break;
    }
    scwin.Combo1_OnItemChanged();
};

/*영수증 재인자 거래시 */

scwin.Btn_receipt_OnClick = async function(e) {
    if (array.GetCheckedRows(0) != 1) {
        $c.iz.data.message("해당 거래를 1개 선택해 주세요");
        return;
    }
    if (array.getCellData(scwin.check_no_2, "onecheck") == "Y") {
        //정상거래 확인 
        if (array.getCellData(scwin.check_no_2, "tranStus").indexOf("정상") < 0) {
            $c.iz.data.alert("영수증 거래는 정상거래에서만 가능합니다.", "알림");
            return;
        }
        cboupgb_copy.setValue(array.getCellData(scwin.check_no_2, "bzwkDstic")); //업무구분
        Combo1_copy.setValue('9'); //조회구분
        inquryDte_copy.setValue(inquryDte.getValue()); //조회일자
        acno_copy.setValue(array.getCellData(scwin.check_no_2, "ntresrAcno")); //국고계좌번호
        ntresrAcno_copy.setValue(''); //전자납부번호
        brncd_copy.setValue(array.getCellData(scwin.check_no_2, "brncd")); //점코드
        tranSerno_copy.setValue(array.getCellData(scwin.check_no_2, "tranSerno")); //거래일련번호 

        $c.iz.tran.setTranID("KGA0400341");
        await $c.iz.tran.ASend();
    }
};

scwin.OnEndTran = function() {
    if ($c.iz._tran.bError == false) {
        //고객정보 마스킹 처리관련 수정, 마우스 이동시 내용 복원
        for (var row = 1; row <= array.getTotalRow(); row++) {

            /*ORG SRC: array.CellTooltip(row, "prNo") = array.GetCellDataSaveName(row, "prNo");*/
            // ✖ = array.getCellData(row, "prNo");
        }
        //고객정보 마스킹 처리관련 수정, 마우스 이동시 내용 복원

    }
};
